            }
        }

internal string GenerateTargetToString(bool targetWrapper, string? targetName = null)
        {
            var targetAttribute = GetType().GetFirstCustomAttribute<TargetAttribute>();
            string targetType = (targetAttribute?.Name ?? GetType().Name).Trim();
            targetWrapper = targetWrapper || targetAttribute?.IsCompound == true || targetAttribute?.IsWrapper == true;
            if (!targetWrapper && targetType.IndexOf("Target", StringComparison.OrdinalIgnoreCase) < 0)
            {
                targetType += "Target";
            }
            targetName = targetName ?? Name;
            if (string.IsNullOrEmpty(targetName))
                return targetWrapper ? targetType : $"{targetType}([unnamed])";
            else
                return $"{targetType}(Name={targetName})";
        }

public override void Triggered(ICalendar? cal)
    {
        timesTriggered++;
        previousFireTimeUtc = nextFireTimeUtc;
        nextFireTimeUtc = GetFireTimeAfter(nextFireTimeUtc);

        if (cal is not null && nextFireTimeUtc.HasValue)
        {
            while (!cal.IsTimeIncluded(nextFireTimeUtc.GetValueOrDefault()))
            {
                nextFireTimeUtc = GetFireTimeAfter(nextFireTimeUtc);

                if (!nextFireTimeUtc.HasValue)
                {
                    break;
                }

                //avoid infinite loop
                if (nextFireTimeUtc.GetValueOrDefault().Year > TriggerConstants.YearToGiveUpSchedulingAt)
                {
                    nextFireTimeUtc = null;
                    break;
                }
            }
        }
    }

public override DateTimeOffset? FinalFireTimeUtc
    {
        get
        {
            if (repeatCount == 0)
            {
                return StartTimeUtc;
            }

            var endTimeUtc = EndTimeUtc;

            if (repeatCount == RepeatIndefinitely && !endTimeUtc.HasValue)
            {
                return null;
            }
            if (repeatCount == RepeatIndefinitely)
            {
                return GetFireTimeBefore(endTimeUtc.GetValueOrDefault());
            }

            DateTimeOffset lastTrigger = StartTimeUtc.AddTicks(repeatCount * repeatInterval.Ticks);

            if (!endTimeUtc.HasValue || lastTrigger < endTimeUtc.GetValueOrDefault())
            {
                return lastTrigger;
            }
            return GetFireTimeBefore(endTimeUtc.GetValueOrDefault());
        }
    }

private async ValueTask<bool> RemoveJobNoLock(JobKey jobKey, CancellationToken cancellationToken)
    {
        bool found = false;
        var triggersForJob = GetTriggerKeysForJobNoLock(jobKey);
        foreach (var key in triggersForJob)
        {
            await RemoveTriggerNoLock(key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false);
            found = true;
        }

        found = jobsByKey.TryRemove(jobKey, out _) || found;
        resumedJobsInPausedGroups.Remove(jobKey);

        if (found)
        {
            if (jobsByGroup.TryGetValue(jobKey.Group, out var grpMap))
            {
                if (grpMap.Remove(jobKey) && grpMap.Count == 0)
                {
                    jobsByGroup.Remove(jobKey.Group);
                }
            }
        }

        return found;
    }

public override DateTimeOffset? GetFireTimeAfter(DateTimeOffset? afterTimeUtc)
    {
        if (!afterTimeUtc.HasValue)
        {
            afterTimeUtc = TimeProvider.GetUtcNow();
        }

        if (StartTimeUtc > afterTimeUtc.Value)
        {
            afterTimeUtc = startTimeUtc.AddSeconds(-1);
        }

        if (EndTimeUtc.HasValue && afterTimeUtc.Value.CompareTo(EndTimeUtc.Value) >= 0)
        {
            return null;
        }

        DateTimeOffset? pot = GetTimeAfter(afterTimeUtc.Value);
        if (EndTimeUtc.HasValue && pot.HasValue && pot.Value > EndTimeUtc.Value)
        {
            return null;
        }

        return pot;
    }

internal static string FormatErrors(IEnumerable<string?> errorMessages)
    {
        var sb = new StringBuilder();
        var errorCount = 1;
        foreach (var message in errorMessages)
        {
            sb.AppendLine(Divider($"Error {errorCount}"));
            var lines = (message ?? string.Empty).Replace("\r\n", "\n").Split('\n');
            var paddedLines = lines.Select(l => string.IsNullOrEmpty(l) ? l : "    " + l);
            sb.AppendLine(string.Join(Environment.NewLine, paddedLines.ToArray()));
            sb.AppendLine();
            errorCount++;
        }

        sb.AppendLine(Divider());

        return sb.ToString().TrimEnd();
    }

internal IDbCommand SetupCommand(IDbConnection cnn, Action<IDbCommand, object?>? paramReader)
        {
            var cmd = cnn.CreateCommand();
            var init = GetInit(cmd.GetType());
            init?.Invoke(cmd);
            if (Transaction is not null)
                cmd.Transaction = Transaction;
            cmd.CommandText = CommandText;
            if (CommandTimeout.HasValue)
            {
                cmd.CommandTimeout = CommandTimeout.Value;
            }
            else if (SqlMapper.Settings.CommandTimeout.HasValue)
            {
                cmd.CommandTimeout = SqlMapper.Settings.CommandTimeout.Value;
            }
            cmd.CommandType = CommandTypeDirect;
            paramReader?.Invoke(cmd, Parameters);
            return cmd;
        }

public void WritePerfCounter(string counter)
        {
            if (!string.IsNullOrEmpty(_perfFile))
            {
                string normalizedCounter = counter.Replace(':', '_');
                lock (_perfLock)
                {
                    try
                    {
                        File.AppendAllLines(_perfFile, new[] { $"{normalizedCounter}:{DateTime.UtcNow.ToString("O")}" });
                    }
                    catch (Exception ex)
                    {
                        _trace.Error(ex);
                    }
                }
            }
        }

public HostTraceListener(string logFileDirectory, string logFilePrefix, int pageSizeLimit, int retentionDays)
            : base()
        {
            ArgUtil.NotNullOrEmpty(logFileDirectory, nameof(logFileDirectory));
            ArgUtil.NotNullOrEmpty(logFilePrefix, nameof(logFilePrefix));
            _logFileDirectory = logFileDirectory;
            _logFilePrefix = logFilePrefix;

            Directory.CreateDirectory(_logFileDirectory);

            if (pageSizeLimit > 0)
            {
                _enablePageLog = true;
                _pageSizeLimit = pageSizeLimit * 1024 * 1024;
                _currentPageSize = 0;
            }

            if (retentionDays > 0)
            {
                _enableLogRetention = true;
                _retentionDays = retentionDays;
            }

            Writer = CreatePageLogWriter();
        }

public override void WriteLine(string message)
        {
            base.WriteLine(message);
            if (_enablePageLog)
            {
                int messageSize = UTF8Encoding.UTF8.GetByteCount(message);
                _currentPageSize += messageSize;
                if (_currentPageSize > _pageSizeLimit)
                {
                    Flush();
                    if (Writer != null)
                    {
                        Writer.Dispose();
                        Writer = null;
                    }

                    Writer = CreatePageLogWriter();
                    _currentPageSize = 0;
                }
            }

            Flush();
        }

private static async Task<HttpRequestMessage> CloneAsync(HttpRequestMessage request, Uri requestUri)
        {
            var clone = new HttpRequestMessage(request.Method, requestUri)
            {
                Version = request.Version
            };

            request.Headers.ForEach(header => clone.Headers.TryAddWithoutValidation(header.Key, header.Value));

            request.Options.ForEach(option => clone.Options.Set(new HttpRequestOptionsKey<object>(option.Key), option.Value));

            if (request.Content != null)
            {
                clone.Content = new ByteArrayContent(await request.Content.ReadAsByteArrayAsync().ConfigureAwait(false));

                request.Content.Headers.ForEach(header => clone.Content.Headers.TryAddWithoutValidation(header.Key, header.Value));
            }

            return clone;
        }

public Task<GrainAddress?> Register(GrainAddress address, GrainAddress? previousAddress)
    {
        ArgumentNullException.ThrowIfNull(address);

        var result = _entries.AddOrUpdate(
            address.GrainId,
            static (grainId, state) => state.Address,
            static (grainId, existing, state) =>
            {
                if (existing is null || state.PreviousAddress is { } prev && existing.Matches(prev) || state.Self.IsSiloDead(existing))
                {
                    return state.Address;
                }

                return existing;
            },
            (Self: this, Address: address, PreviousAddress: previousAddress));

        if (result is null || IsSiloDead(result))
        {
            return Task.FromResult<GrainAddress?>(null);
        }

        return Task.FromResult<GrainAddress?>(result);
    }

public void CleanupDefunctSiloEntries(DateTimeOffset beforeDate)
        {
            lock (_lock)
            {
                var entries = _table.Values.ToList();
                foreach (var (entry, _) in entries)
                {
                    if (entry.Status != SiloStatus.Active
                        && new DateTime(Math.Max(entry.IAmAliveTime.Ticks, entry.StartTime.Ticks), DateTimeKind.Utc) < beforeDate)
                    {
                        _table.Remove(entry.SiloAddress, out _);
                    }
                }
            }
        }

